def minimax(node, depth, maximizingPlayer):
 if depth == 0 or node.is_terminal():
 return node.heuristic_value()
 if maximizingPlayer:
 value = float('-inf')
 for child in node.children:
 value = max(value, minimax(child, depth-1, False))
 return value
 else:
 value = float('inf')
 for child in node.children:
 value = min(value, minimax(child, depth-1, True))
 return value

#include <stdio.h>
#include <limits.h>

typedef struct Node {
 int value;
 struct Node* children;
} Node;

int alpha_beta_pruning(Node* node, int depth, int alpha, int beta, int maximizingPlayer) {
 if (depth == 0 || node->value != 0) {
 return node->value;
 }
 if (maximizingPlayer) {
 int value = INT_MIN;
 for (Node* child = node->children; child != NULL; child = child->children) {
 value = max(value, alpha_beta_pruning(child, depth-1, alpha, beta, 0));
 alpha = max(alpha, value);
 if (alpha >= beta) {
 break;
 }
 }
 return value;
 } else {
 int value = INT_MAX;
 for (Node* child = node->children; child != NULL; child = child->children) {
 value = min(value, alpha_beta_pruning(child, depth-1, alpha, beta, 1));
 beta = min(beta, value);
 if (beta <= alpha) {
 break;
 }
 }
 return value;
 }
